package transactions

import (
	"context"
	"fmt"
	"time"

	"github.com/alpacahq/alpacadecimal"

	"github.com/openmeterio/openmeter/openmeter/customer"
	"github.com/openmeterio/openmeter/openmeter/ledger"
	"github.com/openmeterio/openmeter/pkg/currencyx"
)

type MyNewTemplate struct {
	At       time.Time
	Amount   alpacadecimal.Decimal
	Currency currencyx.Code
}

func (t MyNewTemplate) Validate() error {
	if t.At.IsZero() {
		return fmt.Errorf("at is required")
	}
	if err := ledger.ValidateTransactionAmount(t.Amount); err != nil {
		return fmt.Errorf("amount: %w", err)
	}
	if err := ledger.ValidateCurrency(t.Currency); err != nil {
		return fmt.Errorf("currency: %w", err)
	}
	return nil
}

func (t MyNewTemplate) typeGuard() guard { return true }

var _ CustomerTransactionTemplate = (MyNewTemplate{})

func (t MyNewTemplate) correct(CorrectionInput) ([]ledger.TransactionInput, error) {
	return nil, templateCorrectionNotImplemented(templateName(t))
}

func (t MyNewTemplate) resolve(ctx context.Context, customerID customer.CustomerID, resolvers ResolverDependencies) (ledger.TransactionInput, error) {
	customerAccounts, err := resolvers.AccountService.GetCustomerAccounts(ctx, customerID)
	if err != nil {
		return nil, fmt.Errorf("get customer accounts: %w", err)
	}
	fbo, err := customerAccounts.FBOAccount.GetSubAccountForRoute(ctx, ledger.CustomerFBORouteParams{
		Currency: t.Currency,
	})
	if err != nil {
		return nil, fmt.Errorf("get FBO sub-account: %w", err)
	}
	// ... resolve target sub-account ...
	return &TransactionInput{
		bookedAt: t.At,
		entryInputs: []*EntryInput{
			{address: fbo.Address(), amount: t.Amount.Neg()},
			// {address: target.Address(), amount: t.Amount},
		},
	}, nil
}
